365	///
366	/// If the current call frame is Lua bytecode (`isLuacode`), the metamethod
367	/// may yield; otherwise yielding is suppressed (`callnoyield`).
368	pub(crate) fn call_tm(
369	    state: &mut LuaState,
370	    f: LuaValue,
371	    p1: LuaValue,
372	    p2: LuaValue,
373	    p3: LuaValue,
374	) -> Result<(), LuaError> {
375	    // C: StkId func = L->top.p;
376	    let func = state.top_idx();
377	    // C: setobj2s(L, func, f);     /* push function (assume EXTRA_STACK) */
378	    // C: setobj2s(L, func + 1, p1); /* 1st argument */
379	    // C: setobj2s(L, func + 2, p2); /* 2nd argument */
380	    // C: setobj2s(L, func + 3, p3); /* 3rd argument */
381	    // C: L->top.p = func + 4;
382	    //
383	    // PORT NOTE: In C these are direct writes into the EXTRA_STACK reserve
384	    // area above the official top.  In Rust we use push() which manages
385	    // capacity; the semantic result is identical.
386	    state.push(f);
387	    state.push(p1);
388	    state.push(p2);
389	    state.push(p3);
390	    // C: if (isLuacode(L->ci))
391	    //      luaD_call(L, func, 0);
392	    //    else
393	    //      luaD_callnoyield(L, func, 0);
394	    //
395	    // TODO(port): `do_call(func, nresults)` vs `call_from(func, nresults)` —
396	    // exact Rust API name TBD; nargs is implicit as `top - func - 1`.
397	    if state.current_ci().is_lua_code() {
398	        state.do_call(func, 0)?;
399	    } else {
400	        state.do_call_no_yield(func, 0)?;
401	    }
402	    Ok(())
403	}
404	
405	// ── luaT_callTMres ───────────────────────────────────────────────────────────
406	
407	// C: void luaT_callTMres (lua_State *L, const TValue *f, const TValue *p1,
408	//                          const TValue *p2, StkId res)
409	/// Call tag method `f` with two arguments, writing the single result into
410	/// the stack slot at index `res`.
411	///
412	/// `res` is a `StackIdx` (index-stable across stack reallocation) that must
413	/// refer to a pre-existing or scratch slot.  After return, the stack top is
414	/// back to what it was before the call (i.e. `top == res`).
415	///
416	/// C uses `savestack`/`restorestack` (byte-offset from base) to preserve `res`
417	/// across potential stack reallocations inside `luaD_call`.  In Rust, `StackIdx`
418	/// is already an index and needs no save/restore.
419	pub(crate) fn call_tm_res(
420	    state: &mut LuaState,
421	    f: LuaValue,
422	    p1: LuaValue,
423	    p2: LuaValue,
424	    res: StackIdx,
425	) -> Result<(), LuaError> {
426	    // C: ptrdiff_t result = savestack(L, res);
